module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output reg [15:0] result
);
// DEFINE STATE PARAMETERS
parameter IDLE = 3'd0;
parameter SUB = 3'd1;
parameter mux_sel_0 = 3'd2;
parameter mux_sel_1 = 3'd3;
parameter shift = 3'd4;
parameter check_cnt = 3'd5;
parameter finish = 3'd6;
// DEFINE INTERNAL REGISTERS
reg [2:0] next_state, state;
reg [4:0] cnt;
reg [16:0] neg_divisor;
reg [16:0] sr;
reg [16:0] sub_result;
reg [16:0] mux_sel;
reg [16:0] carry_out;
// DEFINE COMBINATIONAL LOGIC
assign mux_sel_0 = (sr[16] == 1'b0) ? 1'b1 : 1'b0;
assign mux_sel_1 = (sr[16] == 1'b1) ? 1'b1 : 1'b0;
// DEFINE SEQUENTIAL LOGIC
always @(posedge clk or posedge rst) begin
    if (rst) begin
        state <= IDLE;
        cnt <= 5'b0;
        neg_divisor <= 17'b0;
        sr <= 17'b0;
    end else begin
        state <= next_state;
        if (state == IDLE) begin
            if (opn_valid == 1'b1) begin
                if (sign == 1'b1) begin
                    sr <= {1'b0, dividend, 8'b0};
                    neg_divisor <= {1'b0, ~divisor + 1'b1, 8'b0};
                end else begin
                    sr <= {1'b0, dividend, 8'b0};
                    neg_divisor <= {1'b0, divisor, 8'b0};
                end
                cnt <= 5'd1;
            end
        end else if (state == shift) begin
            sr <= {sr[15:0], carry_out[0]};
            cnt <= cnt + 5'd1;
        end else if (state == finish) begin
            cnt <= 5'b0;
            if (sign == 1'b1) begin
                sr <= {1'b0, sr[15:0]};
            end else begin
                sr <= sr;
            end
        end
    end
end
always @(*) begin
    case (state)
        IDLE: begin
            if (opn_valid == 1'b1) begin
                next_state = SUB;
            end else begin
                next_state = IDLE;
            end
        end
        SUB: begin
            sub_result = sr - neg_divisor;
            carry_out = sub_result[16] ? sr - neg_divisor + 17'b1 : sr - neg_divisor;
            next_state = mux_sel;
        end
        mux_sel_0: begin
            if (carry_out[16] == 1'b1) begin
                next_state = shift;
            end else begin
                next_state = check_cnt;
            end
        end
        mux_sel_1: begin
            if (carry_out[16] == 1'b1) begin
                next_state = shift;
            end else begin
                next_state = check_cnt;
            end
        end
        shift: begin
            next_state = check_cnt;
        end
        check_cnt: begin
            if (cnt[4] == 1'b1) begin
                next_state = finish;
            end else begin
                next_state = SUB;
            end
        end
        finish: begin
            if (res_valid == 1'b1) begin
                next_state = IDLE;
            end else begin
                next_state = finish;
            end
        end
        default: begin
            next_state = IDLE;
        end
    endcase
end
always @(posedge clk or posedge rst) begin
    if (rst) begin
        res_valid <= 1'b0;
    end else begin
        if (cnt[4] == 1'b1) begin
            res_valid <= 1'b1;
        end else begin
            if (res_valid == 1'b1) begin
                res_valid <= 1'b0;
            end else begin
                res_valid <= res_valid;
            end
        end
    end
end
always @(posedge clk or posedge rst) begin
    if (rst) begin
        result <= 16'b0;
    end else begin
        if (cnt[4] == 1'b1) begin
            result <= {sr[15:0], sr[16]};
        end else begin
            result <= result;
        end
    end
end
endmodule
